/**
 * course.js — Shared JavaScript for all course unit pages.
 *
 * Bootstrap 5 handles: accordions, tabs, collapse panels.
 * This file handles: multiple-choice quiz logic.
 *
 * Functions are called via inline onclick attributes in the HTML
 * generated by macros/course.njk.
 */

'use strict';

/* ── Multiple-choice quiz ───────────────────────────────────────────── */

/**
 * Check the selected answer in a quiz.
 * Called by the "Check Answer" button inside .course-quiz.
 * @param {HTMLElement} btn - the button that was clicked
 */
function checkQuiz(btn) {
  const quiz = btn.closest('.course-quiz');
  const selected = quiz.querySelector('input[type="radio"]:checked');

  if (!selected) {
    btn.textContent = 'Please select an option first';
    setTimeout(() => { btn.textContent = 'Check Answer'; }, 2000);
    return;
  }

  const correct  = parseInt(quiz.dataset.correct, 10);
  const chosen   = parseInt(selected.value, 10);
  const isRight  = chosen === correct;

  // Show feedback panel
  const feedback    = quiz.querySelector('.quiz-feedback');
  const correctEl   = quiz.querySelector('.quiz-correct');
  const incorrectEl = quiz.querySelector('.quiz-incorrect');

  feedback.classList.remove('d-none');
  correctEl.classList.toggle('d-none', !isRight);
  incorrectEl.classList.toggle('d-none', isRight);

  // Colour the options
  quiz.querySelectorAll('.quiz-option').forEach((opt, i) => {
    opt.classList.remove('quiz-option-correct', 'quiz-option-incorrect');
    if (i === correct) {
      opt.classList.add('quiz-option-correct');
    } else if (i === chosen && !isRight) {
      opt.classList.add('quiz-option-incorrect');
    }
  });

  // Lock the check button; keep reset available
  btn.disabled = true;

  // Disable all radio inputs so the answer can't be changed
  quiz.querySelectorAll('input[type="radio"]').forEach(r => { r.disabled = true; });
}

/**
 * Reset a quiz to its initial state.
 * Called by the "Reset" button inside .course-quiz.
 * @param {HTMLElement} btn - the button that was clicked
 */
function resetQuiz(btn) {
  const quiz = btn.closest('.course-quiz');

  // Uncheck and re-enable radios
  quiz.querySelectorAll('input[type="radio"]').forEach(r => {
    r.checked  = false;
    r.disabled = false;
  });

  // Hide feedback
  quiz.querySelector('.quiz-feedback').classList.add('d-none');
  quiz.querySelector('.quiz-correct').classList.add('d-none');
  quiz.querySelector('.quiz-incorrect').classList.add('d-none');

  // Remove option colouring
  quiz.querySelectorAll('.quiz-option').forEach(opt => {
    opt.classList.remove('quiz-option-correct', 'quiz-option-incorrect');
  });

  // Re-enable check button
  const checkBtn = quiz.querySelector('.quiz-check-btn');
  checkBtn.disabled    = false;
  checkBtn.textContent = 'Check Answer';
}
